codeComparison.old:
/* Fixed sizes — jumps at breakpoints */
h1 { font-size: 24px; }
@media (min-width: 768px) {
  h1 { font-size: 36px; }
}
@media (min-width: 1024px) {
  h1 { font-size: 48px; }
}

codeComparison.new:
/* Fluid — smooth scaling, no breakpoints needed */
:root {
  --text-2xl: clamp(2rem, 5vw, 4rem);
  --text-xl: clamp(1.5rem, 3.5vw, 2.5rem);
  --text-base: clamp(1rem, 2vw, 1.25rem);
  --space-md: clamp(1.5rem, 3vw, 2.5rem);
}

h1 { font-size: var(--text-2xl); }
h2 { font-size: var(--text-xl); }
p { font-size: var(--text-base); }

